command:
const hp = actor?.system?.attributes?.hp;
if (!hp) return;

const name = actor.name;
const pct = hp.pct;
let text, fill;
if (pct <= 25) {
  text = `${name} is gravely wounded!`;
  fill = "#ff2020";
} else if (pct <= 50) {
  text = `${name} is looking hurt`;
  fill = "#ff8800";
} else {
  return;
}

const t = token?.object ?? token;
if (!t) return;

canvas.interface.createScrollingText(t.center, text, {
  anchor: CONST.TEXT_ANCHOR_POINTS.TOP,
  direction: CONST.TEXT_ANCHOR_POINTS.TOP,
  duration: 2500,
  fontFamily: "Modesto Condensed",
  fontSize: 36,
  fill,
  stroke: "#000000",
  strokeThickness: 4
});
